#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X, H; scanf("%lld %lld", &X, &H);
        long long d = X/2; // X is even
        long long first = 5*d;
        long long ans;
        if(H <= first){
            ans = (H + d - 1) / d;
        } else {
            long long rem = H - first;
            long long extra = (rem + X - 1) / X;
            ans = 5 + extra;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

