#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        X = int(next(it)); H = int(next(it))
        d = X // 2
        first = 5 * d
        if H <= first:
            ans = (H + d - 1) // d
        else:
            rem = H - first
            extra = (rem + X - 1) // X
            ans = 5 + extra
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

